        int[] dep = new int[61];
        for (int i = 1; i <= 60; i++) {
            if (i == 1) {
                dep[i] = 0;
            } else {
                int pop = Integer.bitCount(i);
                dep[i] = 1 + dep[pop];
            }
        }

        Set<Integer> T = new HashSet<>();
        for (int a = 1; a <= 60; a++) {
            if (dep[a] == k - 1) {
